import React from "react";
import { useNavigate } from "react-router-dom";

function Home() {

  const navigate = useNavigate();

  const features = [
    {
      title: "Live Tracking",
      icon: "📍",
      desc: "Track your journey live",
      action: () => navigate("/journey"),
    },
    {
      title: "Emergency",
      icon: "🚨",
      desc: "Send alert instantly",
      action: () => navigate("/sos"),
    },
    {
      title: "Police Help",
      icon: "🚓",
      desc: "Nearby stations",
      action: () => navigate("/police"),
    },
    {
      title: "Share Location",
      icon: "📲",
      desc: "Send live location",
      action: () => navigate("/share"),
    },
  ];

  return (
    <div className="home">

      {/* TOP GREETING */}
      <div className="home-header">
        <h2>👋 Stay Safe</h2>
        <p>Your safety companion</p>
      </div>

      {/* MAIN ACTION CARD */}
      <div className="main-card">

        <h1>Start Safe Journey 💖</h1>

        <p>Track, share & stay protected in real-time</p>

        <button
          className="start-btn"
          onClick={() => navigate("/journey")}
        >
          🚀 Start Journey
        </button>

      </div>

      {/* QUICK ACTIONS */}
      <div className="quick-grid">

        {features.map((item, i) => (
          <div
            key={i}
            className="quick-card"
            onClick={item.action}
          >
            <div className="icon">{item.icon}</div>
            <h3>{item.title}</h3>
            <p>{item.desc}</p>
          </div>
        ))}

      </div>

      {/* SOS FLOATING BUTTON */}
      <button
        className="floating-sos"
        onClick={() => navigate("/sos")}
      >
        🚨
      </button>

    </div>
  );
}

export default Home;
